void selection_sort_int(int* arr, int n, int* comparisons, int* swaps) {
    for (int i = 0; i < n - 1 ; i++) {
        int min_index = i;
        for (int j = i + 1; j < n; j++) {
            if (arr[j] < arr[min_index]) {
                min_index = j;
            }
            (*comparisons)++;
        }
        if (min_index != i) {
            int temp = arr[i];
            arr[i] = arr[min_index];
            arr[min_index] = temp;
            (*swaps)++;
        }
    }
}

void selection_sort_float(float* arr, int n, int* comparisons, int* swaps) {
    for (int i = 0; i < n - 1 ; i++) {
        int min_index = i;
        for (int j = i + 1; j < n; j++) {
            if (arr[j] < arr[min_index]) {
                min_index = j;
            }
            (*comparisons)++;
        }
        if (min_index != i) {
            float temp = arr[i];
            arr[i] = arr[min_index];
            arr[min_index] = temp;
