Thought: I need to implement a Java class `LogAnalyzer` that tracks request times and calculates average, median, and mode. I'll use two PriorityQueues (heaps) for the median and a HashMap for the mode. I will write this to a file named `LogAnalyzer.java`.
<code>
content = "import java.util.*;

public class LogAnalyzer {
    private PriorityQueue<Long> maxHeap;
    private PriorityQueue<Long> minHeap;
    private HashMap<Long, Integer> requestTimeFreq;
    private long totalRequestTime;
    private int totalRequests;

    public LogAnalyzer() {
        maxHeap = new PriorityQueue<>(Comparator.reverseOrder());
        minHeap = new PriorityQueue<>();
        requestTimeFreq = new HashMap<>();
        totalRequestTime = 0;
        totalRequests = 0;
    }

    public synchronized void addRequestTime(long time) {
        totalRequestTime += time;
        totalRequests++;
        requestTimeFreq.put(time, requestTimeFreq.getOrDefault(time, 0) + 1);

        if (maxHeap.isEmpty() || time <= maxHeap.peek()) {
            maxHeap.add(time);
        } else {
            minHeap.add(time);
        }

        // Balance heaps for median calculation
        if (maxHeap.size() > minHeap.size() + 1) {
            minHeap.add(maxHeap.poll());
        } else if (minHeap.size() > maxHeap.size()) {
            maxHeap.add(minHeap.poll());
        }
    }

    public synchronized double getAverage() {
        return totalRequests == 0 ? 0 : (double) totalRequestTime / totalRequests;
    }

    public synchronized double getMedian() {
        if (totalRequests == 0) return 0;
        if (maxHeap.size() == minHeap.size()) {
            return (maxHeap.peek() + minHeap.peek()) / 2.0;
        }
        return maxHeap.peek();
    }

    public synchronized long getMode() {
        long mode = -1;
        int maxFreq = -1;
        for (Map.Entry<Long, Integer> entry : requestTimeFreq.entrySet()) {
            if (entry.getValue() > maxFreq) {
                maxFreq = entry.getValue();
                mode = entry.getKey();
            }
        }
        return mode;
    }

    public void logStats() {
        System.out.println("Average: " + getAverage());
        System.out.println("Median: " + getMedian());
        System.out.println("Mode: " + getMode());
    }

    public static void main(String[] args) {
        LogAnalyzer analyzer = new LogAnalyzer();
        analyzer.addRequestTime(100);
        analyzer.addRequestTime(200);
        analyzer.addRequestTime(100);
        analyzer.addRequestTime(300);
        analyzer.addRequestTime(400);
        analyzer.logStats();
    }
