<code>
content = "import math
from concurrent.futures import ProcessPoolExecutor

# Memoization for DP
memo = {}

def hept(n):
    # Input validation and rounding
    try:
        if isinstance(n, (int, float)):
            n = int(round(n))
        else:
            raise ValueError('Input must be a number')

        if n < 1:
            return 'Error: Input must be a positive integer.'
        if n > 2000:
            return 'Error: Input surpasses the limit of 2000.'
    except (ValueError, TypeError) as e:
        return f'Error: {str(e)}'

    # DP/Recursive approach: Heptagonal formula is n(5n-3)/2
    # To make it recursive with DP: H(n) = H(n-1) + 5n - 5 (for n > 1)
    if n == 1:
        return 1
    if n in memo:
        return memo[n]

    # Using a loop to avoid recursion depth issues (simulating tail recursion)
    res = 1
    for i in range(2, n + 1):
        res += 5 * i - 5

    memo[n] = res
    return res

def get_sequence_info(n):
    try:
        n_val = int(round(n)) if isinstance(n, (int, float)) else None
        if n_val is None or n_val < 1 or n_val > 2000:
            return 'Error: Invalid input for sequence generation.'

        seq = [hept(i) for i in range(1, n_val + 1)]
        total_sum = sum(seq)
        total_prod = 1
        for x in seq: total_prod *= x
        return {'sequence': seq, 'sum': total_sum, 'product': total_prod}
    except Exception as e:
        return f'Error: {str(e)}'

def handle_query(query):
    if isinstance(query, tuple) or isinstance(query, list) and len(query) == 2 and all(isinstance(x, (int, float)) for x in query):
        # Handle range
        start, end = int(round(query[0])), int(round(query[1]))
        if start > end or start < 1:
            return 'Error: Invalid range.'
        return [hept(i) for i in range(start, end + 1)]
    elif isinstance(query, (int, float)):
        return hept(query)
    else:
        return 'Error: Unsupported query format.'

def parallel_process(queries):
    with ProcessPoolExecutor() as executor:
        return list(executor.map(handle_query, queries))

if __name__ == '__main__':
    # Testing basic functionality
    print(f'Hept(10): {hept(10)}')
    print(f'Sequence(5): {get_sequence_info(5)}')
    print(f'Range(10, 15): {handle_query((10, 15))}')
"
