let topic = process.env.MQTT_TOPIC || 'sensors/data';

client.on('connect', function () {
  console.log('Connected to MQTT broker');
  client.subscribe(topic);
});

client.on('message', async function (topic, message) {
  try {
    // Stage 1: Data Procurement
    let mqttMessage = message.toString();
    console.log(`Received MQTT message: ${mqttMessage}`);

    // Stage 2: Transformation and Duplication Check
    let ts = moment().unix(); 
    let payload = JSON.parse(mqttMessage);
    let messageId = payload.id || mqttMessage; // Use unique message ID if available

    let duplicateCheckParams = {
        TableName: 'mqttMessages',
        KeyConditionExpression: '#msg = :mqttMessage',
        ExpressionAttributeNames: {
            '#msg': 'message'
        },
        ExpressionAttributeValues: {
            ':mqttMessage': mqttMessage
        }
    };

    let previousMessages = await documentClient.query(duplicateCheckParams).promise();
    if (previousMessages.Items.length > 0) {
        console.log('Duplicate message detected. Skipping...');
        return;
    }

    // Stage 3: Data Preservation (Time-series format)
    let newRecord = {
        TableName: 'mqttMessages',
        Item: {
            id: 'mqtt-' + ts + '-' + Math.random().toString(36).substr(2, 9),
            timestamp: ts,
            message: mqttMessage,
            transformedData: payload,
            status: 'preserved'
        }
    };

    await documentClient.put(newRecord).promise();
    console.log('Data successfully preserved in TSDB');

