const express = require('express')
const mongoose = require('mongoose')
const app = express()
app.use(express.json())

const inventorySchema = new mongoose.Schema({
    product: String,
    quantity: Number,
    __v: { type: Number, default: 0}
});
const Inventory = mongoose.model('Inventory', inventorySchema)

app.patch('/updateInventory/:productId', async (req, res) => {
  const versionAtUpdate = req.body.__v;
  try {
    const inventory = await Inventory.findOne({product: req.params.productId});
    if (!inventory) return res.status(404).send("Product not found");

    if (versionAtUpdate !== inventory.__v) {
      return res.status(409).send("Conflict detected, please refresh your data");
    }

    inventory.quantity = req.body.quantity;
    await inventory.save();
    res.send('Inventory updated successfully');
  } catch(err) {
    res.status(500).send("Error updating inventory");
  }
})
